$style = @'
    <style>
        .club-page{max-width:800px;margin:0 auto;padding:3rem 1.5rem 6rem}.club-page .club-title{text-align:center;font-size:3.5rem;font-weight:800;color:var(--text-main);margin-bottom:1rem;letter-spacing:-1px}.club-page .club-subtitle{text-align:center;font-size:1.15rem;color:var(--text-muted);max-width:600px;margin:0 auto 2.5rem;line-height:1.7;position:relative;padding-top:1.5rem}.club-page .club-subtitle::before{content:'';position:absolute;top:0;left:50%;transform:translateX(-50%);width:60px;height:3px;background:var(--accent-cyan);border-radius:3px}.club-hero-image{width:100%;border-radius:24px;overflow:hidden;margin-bottom:4rem;box-shadow:var(--shadow-xl)}.club-hero-image img{width:100%;height:auto;display:block;aspect-ratio:16/9;object-fit:cover}.club-section{margin-bottom:4rem}.club-section h2{font-size:2rem;font-weight:800;color:var(--text-main);margin-bottom:1.5rem;text-align:center}.club-section p{font-size:1.1rem;color:var(--text-muted);line-height:1.8;text-align:center}.club-section .club-image{width:100%;border-radius:20px;overflow:hidden;margin:2rem 0;box-shadow:var(--shadow-md)}.club-section .club-image img{width:100%;height:auto;display:block;aspect-ratio:16/9;object-fit:cover}.club-cta{background:linear-gradient(135deg,#e57b25 0%,#9b59b6 50%,var(--primary) 100%);border-radius:24px;padding:3.5rem 2.5rem;text-align:center;color:white;margin-top:4rem}.club-cta h3{font-size:1.8rem;font-weight:700;color:white;margin-bottom:1.5rem;line-height:1.4}.club-cta .cta-btn{display:inline-flex;align-items:center;gap:.75rem;background:white;color:var(--primary);padding:.9rem 2rem;border-radius:50px;font-weight:700;font-size:1.05rem;transition:all .3s ease;box-shadow:0 4px 15px rgba(0,0,0,.15)}.club-cta .cta-btn:hover{transform:translateY(-3px);box-shadow:0 8px 25px rgba(0,0,0,.25)}.club-nav{display:flex;justify-content:space-between;gap:1rem;margin-top:4rem}.club-nav a{display:inline-flex;align-items:center;gap:.5rem;background:var(--primary);color:white;padding:.9rem 2rem;border-radius:50px;font-weight:600;transition:all .3s ease}.club-nav a:hover{transform:translateY(-3px);box-shadow:0 8px 20px rgba(44,76,126,.3)}@media(max-width:768px){.club-page .club-title{font-size:2.5rem}.club-page{padding:2rem 1rem 4rem}.club-nav{flex-direction:column}.club-nav a{justify-content:center}}
    </style>
'@

